# DNS cache tuning
$dns = "HKLM:\SYSTEM\CurrentControlSet\Services\Dnscache\Parameters"
RegSet $dns "MaxCacheTtl"                86400
RegSet $dns "MaxNegativeCacheTtl"         0
RegSet $dns "NegativeSOACacheTime"        0
RegSet $dns "NetFailureCacheTime"         0
