        RegSet $nvDrv "EnableCEPreemption"         0
        RegSet $nvDrv "EnableMidGfxPreemptionVGPU" 0
        RegSet $nvDrv "EnableGrGfxPreemption"      0
        RegSet $nvDrv "DisablePreemption"          1
    }
    RegSet $nvDrv "RMGpsBandwidthBoostEnable" 1
    RegSet $nvDrv "RMDeepL2"                  0
    RegSet $nvDrv "RMFastGC"                  1
    RegSet $nvDrv "GpuPowerPolicy"            1
    RegSet $nvDrv "OverrideMaxPerf"           1
    RegSet $nvDrv "RmGdiSharedMemoryPoolSize" 0
    RegSet $nvDrv "NvContextPrimary"          1
    RegSet $nvDrv "RmProfilingAdminOnly"      0
    RegSet $nvDrv "RmDisableGpuTimeout"       1
    RegSet $nvDrv "RmVsyncAlwaysOff"          0
    RegSet $nvDrv "RmGlobalMaxFrameLatency"   1

    # NVIDIA Control Panel keys
    $nvcpKey = "HKLM:\SOFTWARE\NVIDIA Corporation\Global"
    If (-not (Test-Path $nvcpKey)) { New-Item $nvcpKey -Force | Out-Null }
    Set-ItemProperty $nvcpKey "DisplayDriverVersion" "" -Type String -EA SilentlyContinue

    $nvTweak = "HKLM:\SOFTWARE\NVIDIA Corporation\Global\NVTweak"
    RegSet $nvTweak "Coolbits"                    24
    RegSet $nvTweak "RMGpsBandwidthBoostEnable"   1
    RegSet $nvTweak "OverrideMaxPerf"             1

    If ($isLaptop) {
        RegSet $nvTweak "PowerMizerEnable"  1
        RegSet $nvTweak "PowerMizerLevel"   1
        RegSet $nvTweak "PowerMizerLevelAC" 1
    } Else {
        # Desktop — max performance ถาวร
        RegSet $nvTweak "PowerMizerEnable"  1
        RegSet $nvTweak "PowerMizerLevel"   3
        RegSet $nvTweak "PowerMizerLevelAC" 3
    }

    # NVIDIA Inspector / Profile settings ผ่าน Registry (NvAPI)
    # เทียบเท่า NvidiaProfileInspector preset สำหรับ GTA V / FiveM
    $nvProfile = "HKCU:\Software\NVIDIA Corporation\Global\NVTweak"
    RegSet $nvProfile "VsyncMode"          0    # Always Off
    RegSet $nvProfile "MaxFramesAllowed"   1    # 1 frame latency (Ultra Low Latency)
    RegSet $nvProfile "TextureFilterAniso" 1    # Application controlled

    # Threaded optimization + Shader cache
    $nvDX = "HKLM:\SOFTWARE\NVIDIA Corporation\Global\DirectX"
    RegSet $nvDX "ThreadedOptimization" 1
    RegSet $nvDX "ShaderCache"          1

    # nvlddmkm service params — ลด DPC latency
    $nvSvc = "HKLM:\SYSTEM\CurrentControlSet\Services\nvlddmkm"
    RegSet $nvSvc "EnableMSHybrid"         0
    RegSet $nvSvc "DisablePowerManagement" 1
    # ไม่ยุ่ง service NVIDIA เลย — reboot จัดการเอง
}

# ---- AMD / RADEON ----
If ($hasAMD) {
    # AMD GPU registry keys
    $amdClass = "HKLM:\SYSTEM\CurrentControlSet\Control\Class\{4d36e968-e325-11ce-bfc1-08002be10318}"
    Get-ChildItem $amdClass -EA SilentlyContinue | Where-Object {
        $_.PSChildName -match "^\d{4}$"
    } | ForEach-Object {
        $drvPath = $_.PSPath
        $drvInfo = Get-ItemProperty $drvPath -EA SilentlyContinue
        If ($drvInfo.DriverDesc -like "*AMD*" -or $drvInfo.DriverDesc -like "*Radeon*") {
            # Power & Performance
            Set-ItemProperty $drvPath "EnableUlps"                   0 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "EnableUlps_NA"                0 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "PP_SclkDeepSleepDisable"      1 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "PP_ThermalAutoThrottlingEnable" 0 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "DisableDMACopy"               0 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "DisableBlockWrite"            0 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "StutterMode"                  0 -Type DWord -EA SilentlyContinue
            # Anti-Lag / Enhanced Sync OFF (ลด latency)
            Set-ItemProperty $drvPath "AntiLag"                      1 -Type DWord -EA SilentlyContinue
            Set-ItemProperty $drvPath "EnableVSync"                  0 -Type DWord -EA SilentlyContinue
            # Texture filter
            Set-ItemProperty $drvPath "TextureFilterQuality"         0 -Type DWord -EA SilentlyContinue
        }
    }

    # AMD Software / Radeon Settings
    $amdSoft = "HKCU:\Software\AMD\DVMSettings"
    RegSet $amdSoft "EnableMSAAAlphaTest" 0

    # Disable AMD telemetry services
    @("AMD External Events Utility","amdfendr","amdow") | ForEach-Object { SvcKill $_ }
}

