# ปิด Maintenance tasks ที่รู้จัก
@(
    "\Microsoft\Windows\TaskScheduler\Regular Maintenance",
    "\Microsoft\Windows\TaskScheduler\Maintenance Configurator",
    "\Microsoft\Windows\Diagnosis\Scheduled",
