        "*EnableAdvancedDynamicITR"     = "0"
        "*PnPCapabilities"              = "24"
        "*DefaultPnPCapabilities"       = "24"
        "*LogLinkStateEvent"            = "16"
        "*OBFFEnabled"                  = "0"
        "*EnableD0PHYFlexibleSpeed"     = "0"
        "*EnablePHYWakeUp"              = "0"
        "*EnablePHYFlexibleSpeed"       = "0"
        "*WakeOnSlot"                   = "0"
        "*PowerDownPll"                 = "0"
        "*EeePhyEnable"                 = "0"
        "*WaitAutoNegComplete"          = "0"
        "*WolShutdownLinkSpeed"         = "2"
        "*WakeFromS5"                   = "0"
        "*WakeOn"                       = "0"
    }
    ForEach ($kv in $nicProps.GetEnumerator()) {
        Set-ItemProperty $p $kv.Key $kv.Value -Type String -EA SilentlyContinue
    }
    # String-type special values
    Set-ItemProperty $p "*Ultra Low Power Mode"      "Disabled" -Type String -EA SilentlyContinue
    Set-ItemProperty $p "*Selective Suspend"         "Disabled" -Type String -EA SilentlyContinue
    Set-ItemProperty $p "*Link Speed Battery Saver"  "Disabled" -Type String -EA SilentlyContinue
    Set-ItemProperty $p "*System Idle Power Saver"   "Disabled" -Type String -EA SilentlyContinue
    Set-ItemProperty $p "*Selective Suspend Idle Timeout" "60"  -Type String -EA SilentlyContinue
}

# ============================================================
# [FINAL] Network Reset + Auto Reboot
# ============================================================
netsh winsock reset            2>$null | Out-Null
netsh int ip reset             2>$null | Out-Null

# ============================================================
# [TR] TIMER RESOLUTION 0.5ms — Auto + FiveM Trigger
# ============================================================

# สร้าง TimerRes.exe (C# inline) — request 0.5ms resolution
$trSrc = @'
using System;
using System.Runtime.InteropServices;
using System.Threading;
class TimerRes {
    [DllImport("ntdll.dll")] static extern int NtSetTimerResolution(uint req, bool set, out uint cur);
    [DllImport("ntdll.dll")] static extern int NtQueryTimerResolution(out uint min, out uint max, out uint cur);
    static void Main(string[] args) {
        uint min, max, cur;
        NtQueryTimerResolution(out min, out max, out cur);
        // 0.5ms = 5000 units (100ns per unit)
        uint target = 5000;
        if (target < max) target = max;
        NtSetTimerResolution(target, true, out cur);
        // keep alive
        while (true) {
            NtSetTimerResolution(target, true, out cur);
            Thread.Sleep(1000);
        }
    }
}
'@

$trDir  = "C:\RMT"
$trExe  = "$trDir\TimerRes.exe"

If (-not (Test-Path $trDir)) { New-Item $trDir -ItemType Directory -Force | Out-Null }

# compile ด้วย csc.exe ที่มาพร้อม .NET Framework
$csc = Get-ChildItem "C:\Windows\Microsoft.NET\Framework*\v*\csc.exe" -EA SilentlyContinue |
       Sort-Object FullName -Descending | Select-Object -First 1 -ExpandProperty FullName

If ($csc) {
    $trCs = "$env:TEMP\TimerRes.cs"
    [IO.File]::WriteAllText($trCs, $trSrc)
    & $csc /nologo /out:$trExe $trCs 2>$null | Out-Null
    Remove-Item $trCs -EA SilentlyContinue
}

# ถ้า compile ได้ — ตั้ง Task Scheduler ให้รันตอน logon (always-on)
If (Test-Path $trExe) {
    # ลบ task เก่าถ้ามี
    schtasks /delete /tn "RMT_TimerRes" /f 2>$null | Out-Null

    # สร้าง task รันตอน logon แบบ hidden (ไม่โผล่ window)
    $xml = @"
<?xml version="1.0" encoding="UTF-16"?>
<Task version="1.3" xmlns="http://schemas.microsoft.com/windows/2004/02/mit/task">
  <RegistrationInfo><Description>RMT Timer Resolution 0.5ms</Description></RegistrationInfo>
  <Triggers><LogonTrigger><Enabled>true</Enabled></LogonTrigger></Triggers>
  <Principals><Principal><RunLevel>HighestAvailable</RunLevel></Principal></Principals>
  <Settings>
    <MultipleInstancesPolicy>IgnoreNew</MultipleInstancesPolicy>
    <DisallowStartIfOnBatteries>false</DisallowStartIfOnBatteries>
    <StopIfGoingOnBatteries>false</StopIfGoingOnBatteries>
    <ExecutionTimeLimit>PT0S</ExecutionTimeLimit>
    <Priority>0</Priority>
    <Hidden>true</Hidden>
  </Settings>
  <Actions><Exec>
    <Command>wscript.exe</Command>
    <Arguments>//nologo //b "$trDir\RunHidden.vbs"</Arguments>
  </Exec></Actions>
</Task>
"@

    # VBScript wrapper — รัน TimerRes.exe โดยไม่โผล่ window เลย
    $vbs = "CreateObject(""WScript.Shell"").Run """"""$trExe"""""", 0, False"
    [IO.File]::WriteAllText("$trDir\RunHidden.vbs", $vbs, [Text.Encoding]::UTF8)
    $xmlPath = "$env:TEMP\RMT_TR.xml"
    [IO.File]::WriteAllText($xmlPath, $xml, [Text.Encoding]::Unicode)
    schtasks /create /tn "RMT_TimerRes" /xml $xmlPath /f 2>$null | Out-Null
    Remove-Item $xmlPath -EA SilentlyContinue

    # รันตอนนี้เลยด้วย (background)
    Start-Process $trExe -WindowStyle Hidden
}

# Registry: GlobalTimerResolutionRequests = 1 (Windows 11 — ให้ทุก process ได้ 0.5ms)
RegSet "HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager\kernel" "GlobalTimerResolutionRequests" 1

Start-Sleep -Seconds 7
Restart-Computer -Force
